    selectedProductKeys = exactFinancingReply.selectedProductKeys;
    if (selectedProductKeys.length > 0) {
      stateDelta.selected_product_keys = selectedProductKeys;
    }
    stateDelta.intent_key = 'price_inquiry';
    stateDelta.funnel_stage = 'interested';
    stateDelta.lead_score_delta = Math.max(Number(stateDelta.lead_score_delta || 0), 10);
    stateDelta.summary = exactFinancingReply.summary;
  }
} else if (shouldOverrideBrandCatalog && requestedBrandKey) {
  const salesCatalogReply = buildBrandCatalogSalesReply(priceCandidates, requestedBrandKey, {
    includeFinancing: asksFinancingIntent,
    financeMode: requestedFinanceMode,
  });
  if (salesCatalogReply) {
    replyText = salesCatalogReply.replyText;
    selectedProductKeys = salesCatalogReply.selectedProductKeys;
    if (selectedProductKeys.length > 0) {
      stateDelta.selected_product_keys = selectedProductKeys;
    }
    stateDelta.intent_key = stateDelta.intent_key || 'price_inquiry';
    stateDelta.funnel_stage = 'interested';
    stateDelta.lead_score_delta = Math.max(Number(stateDelta.lead_score_delta || 0), 8);
    stateDelta.summary = salesCatalogReply.summary;
  }
}

if (base.router_output?.route_key === 'exact_product_quote') {
  replyText = replyText.replace(
    /Si quer[eé]s,\s*te paso el link de pago[^.]*\.?/gi,
    'Si querés, te cuento cómo avanzar con la compra.'
  );

  if (!asksBuyingStep) {
    replyText = replyText
      .replace(/Para avanzar con la compra[^.]*\.?/gi, '')
      .replace(/Pod[eé]s iniciar la compra[^.]*\.?/gi, '')
      .replace(/Si prefer[ií]s avanzar online[^.]*\.?/gi, '')
      .trim();
  }
}

if (!asksFinancingIntent && offeredPayment == null) {
  replyText = replyText
    .replace(/\b(?:o|y)\s+en\s+\d+\s+cuotas?\b[^.!?]*[.!?]?/gi, ' ')
    .replace(/\b(?:en|son|quedan|sale[n]?)\s+\d+\s+cuotas?\s+(?:de|sin|con)\b[^.!?]*[.!?]?/gi, ' ')
    .replace(/\b\d+\s+cuotas?\s+sin\s+inter[eé]s[^.!?]*[.!?]?/gi, ' ')
    .replace(/\b\d+\s+cuotas?\s+de\s+ARS[^.!?]*[.!?]?/gi, ' ')
    .replace(/\bcuotas?\s+sin\s+inter[eé]s\b[^.!?]*[.!?]?/gi, ' ')
    .replace(/\s{2,}/g, ' ')
    .replace(/\s+([.,!?])/g, '$1')
    .trim();
  replyText = normalizeArgentineTone(replyText);
}

replyText = normalizeArgentineTone(replyText);

return [{
  json: {
    ...base,
    responder_output: {
      route_key: base.router_output?.route_key || 'generic_sales',
      reply_text: replyText,
      selected_product_keys: selectedProductKeys,
      actions,
      state_delta: stateDelta,
    },
    responder_provider_name: 'groq',
    responder_model_name: base.responder_model_name || 'qwen/qwen3-32b',
    responder_raw_text: rawText,
  }
}];
